#include <stdio.h>
#include <string.h>
int main(){
    char s[101];
    scanf("%100s", s);
    int l = 0, r = strlen(s) - 1;
    while(l < r){
        char tmp = s[l];
        s[l] = s[r];
        s[r] = tmp;
        ++l; --r;
    }
    printf("%s\n", s);
    return 0;
}

