#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    string s;
    cin >> s;
    int l = 0, r = s.size() - 1;
    while(l < r){
        swap(s[l], s[r]);
        ++l; --r;
    }
    cout << s << "\n";
    return 0;
}

